SELECT name, value
FROM model_performance_metrics
WHERE created_at = '2023-10-01 12:00:00';

SELECT model_type
  FROM model_configs
  WHERE is_active = 1;

SELECT run_id 
FROM training_runs 
ORDER BY run_id;

SELECT AVG(loss) AS average_loss
FROM training_logs
WHERE run_id = 1;

SELECT MAX(value) AS max_perplexity
FROM model_performance_metrics
WHERE performance_id = 0 AND name = 'perplexity';
